  ('aboriginal-a5729396-moex-00570', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '關於國家賠償責任之成立，下列敘述何者正確？', '["如為檢察官所為，應就其追訴案件犯職務上之罪，經判決有罪確定", "如為受委託行使公權力團體所為，必須公務員就其指揮監督有故意或過失", "如為怠於執行職務之行為，僅限於公務員有故意或重大過失之情形", "公務員係指依法令服務於國家、地方自治團體所屬機關而具有法定職務權限者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
