  ('aboriginal-a5729396-moex-00572', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '關於行政法院管轄權之敘述，下列何者錯誤？', '["以行政機關為被告起訴，原則上由該機關所在地之行政法院管轄", "以公司為被告起訴，由該公司之主事務所或主營業所所在地之行政法院管轄", "以一般人民為被告起訴，由被告住所地之行政法院管轄", "因不動產徵收涉訟者，專屬作成徵收處分機關所在地之行政法院管轄"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
